89	// Buffer
90	impl Buffer for ZBuf {
91	    #[inline(always)]
92	    fn len(&self) -> usize {
93	        self.slices
94	            .as_ref()
95	            .iter()
96	            .fold(0, |len, slice| len + slice.len())
97	    }
98	
99	    #[inline(always)]
100	    fn is_empty(&self) -> bool {
101	        // optimize compared to default implementation by avoiding the walkthouh
102	        for slice in self.slices.as_ref() {
103	            if !slice.is_empty() {
104	                return false;
105	            }
106	        }
107	        true
108	    }
109	}
110	
111	// SplitBuffer
112	impl SplitBuffer for ZBuf {
113	    type Slices<'a> = iter::Map<core::slice::Iter<'a, ZSlice>, fn(&'a ZSlice) -> &'a [u8]>;
114	
115	    fn slices(&self) -> Self::Slices<'_> {
116	        self.slices.as_ref().iter().map(ZSlice::as_slice)
117	    }
118	}
119	
120	impl PartialEq for ZBuf {
121	    fn eq(&self, other: &Self) -> bool {
122	        let mut self_slices = self.slices();
123	        let mut other_slices = other.slices();
124	        let mut current_self = self_slices.next();
125	        let mut current_other = other_slices.next();
126	        loop {
127	            match (current_self, current_other) {
128	                (None, None) => return true,
129	                (None, _) | (_, None) => return false,
130	                (Some(l), Some(r)) => {
131	                    let cmp_len = l.len().min(r.len());
132	                    // SAFETY: cmp_len is the minimum length between l and r slices.
133	                    let lhs = crate::unsafe_slice!(l, ..cmp_len);
134	                    let rhs = crate::unsafe_slice!(r, ..cmp_len);
135	                    if lhs != rhs {
136	                        return false;
137	                    }
138	                    if cmp_len == l.len() {
139	                        current_self = self_slices.next();
140	                    } else {
141	                        // SAFETY: cmp_len is the minimum length between l and r slices.
142	                        let lhs = crate::unsafe_slice!(l, cmp_len..);
143	                        current_self = Some(lhs);
144	                    }
145	                    if cmp_len == r.len() {
146	                        current_other = other_slices.next();
147	                    } else {
148	                        // SAFETY: cmp_len is the minimum length between l and r slices.
149	                        let rhs = crate::unsafe_slice!(r, cmp_len..);
150	                        current_other = Some(rhs);
151	                    }
152	                }
153	            }
154	        }
155	    }
156	}
