158	// From impls
159	impl From<ZSlice> for ZBuf {
160	    fn from(t: ZSlice) -> Self {
161	        let mut zbuf = ZBuf::empty();
162	        zbuf.push_zslice(t);
163	        zbuf
164	    }
165	}
