187	// Reader
188	#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
189	pub struct ZBufPos {
190	    slice: usize,
191	    byte: usize,
192	}
193	
194	#[derive(Debug, Clone)]
195	pub struct ZBufReader<'a> {
196	    inner: &'a ZBuf,
197	    cursor: ZBufPos,
198	}
199	
200	impl Buffer for ZBufReader<'_> {
201	    fn len(&self) -> usize {
202	        self.remaining()
203	    }
204	
205	    fn is_empty(&self) -> bool {
206	        self.cursor.slice >= self.inner.slices.len()
207	    }
208	}
209	
210	impl<'a> HasReader for &'a ZBuf {
211	    type Reader = ZBufReader<'a>;
212	
213	    fn reader(self) -> Self::Reader {
214	        ZBufReader {
215	            inner: self,
216	            cursor: ZBufPos { slice: 0, byte: 0 },
217	        }
218	    }
219	}
220	
221	impl Reader for ZBufReader<'_> {
222	    fn read(&mut self, mut into: &mut [u8]) -> Result<NonZeroUsize, DidntRead> {
223	        let mut read = 0;
224	        while let Some(slice) = self.inner.slices.get(self.cursor.slice) {
225	            // Subslice from the current read slice
226	            // SAFETY: validity of self.cursor.byte is ensured by the read logic.
227	            let from = crate::unsafe_slice!(slice.as_slice(), self.cursor.byte..);
228	            // Take the minimum length among read and write slices
229	            let len = from.len().min(into.len());
230	            // Copy the slice content
231	            // SAFETY: len is the minimum length between from and into slices.
232	            let lhs = crate::unsafe_slice_mut!(into, ..len);
233	            let rhs = crate::unsafe_slice!(from, ..len);
234	            lhs.copy_from_slice(rhs);
235	            // Advance the write slice
236	            // SAFETY: len is the minimum length between from and into slices.
237	            into = crate::unsafe_slice_mut!(into, len..);
238	            // Update the counter
239	            read += len;
240	            // Move the byte cursor
241	            self.cursor.byte += len;
242	            // We consumed all the current read slice, move to the next slice
243	            if self.cursor.byte == slice.len() {
244	                self.cursor.slice += 1;
245	                self.cursor.byte = 0;
246	            }
247	            // We have read everything we had to read
248	            if into.is_empty() {
249	                break;
250	            }
251	        }
252	        NonZeroUsize::new(read).ok_or(DidntRead)
253	    }
254	
255	    fn read_exact(&mut self, into: &mut [u8]) -> Result<(), DidntRead> {
256	        let len = Reader::read(self, into)?;
257	        if len.get() == into.len() {
258	            Ok(())
259	        } else {
260	            Err(DidntRead)
261	        }
262	    }
263	
264	    fn remaining(&self) -> usize {
265	        // SAFETY: self.cursor.slice validity is ensured by the reader
266	        let s = crate::unsafe_slice!(self.inner.slices.as_ref(), self.cursor.slice..);
267	        s.iter().fold(0, |acc, it| acc + it.len()) - self.cursor.byte
268	    }
269	
270	    fn read_zslices<F: FnMut(ZSlice)>(&mut self, len: usize, mut f: F) -> Result<(), DidntRead> {
271	        if self.remaining() < len {
272	            return Err(DidntRead);
273	        }
274	
275	        let iter = ZBufSliceIterator {
276	            reader: self,
277	            remaining: len,
278	        };
279	        for slice in iter {
280	            f(slice);
281	        }
282	
283	        Ok(())
284	    }
285	
286	    fn read_zslice(&mut self, len: usize) -> Result<ZSlice, DidntRead> {
287	        if self.remaining() < len {
288	            return Err(DidntRead);
289	        }
290	        let slice = self.inner.slices.get(self.cursor.slice).ok_or(DidntRead)?;
291	        match (slice.len() - self.cursor.byte).cmp(&len) {
292	            cmp::Ordering::Less => {
293	                let mut buffer = crate::vec::uninit(len);
294	                Reader::read_exact(self, &mut buffer)?;
295	                Ok(buffer.into())
296	            }
297	            cmp::Ordering::Equal => {
298	                let s = slice.subslice(self.cursor.byte..).ok_or(DidntRead)?;
299	                self.cursor.slice += 1;
300	                self.cursor.byte = 0;
301	                Ok(s)
302	            }
303	            cmp::Ordering::Greater => {
304	                let start = self.cursor.byte;
305	                self.cursor.byte += len;
306	                slice.subslice(start..self.cursor.byte).ok_or(DidntRead)
307	            }
308	        }
309	    }
310	
311	    fn read_u8(&mut self) -> Result<u8, DidntRead> {
312	        let slice = self.inner.slices.get(self.cursor.slice).ok_or(DidntRead)?;
313	
314	        let byte = *slice.get(self.cursor.byte).ok_or(DidntRead)?;
315	        self.cursor.byte += 1;
316	        if self.cursor.byte == slice.len() {
317	            self.cursor.slice += 1;
318	            self.cursor.byte = 0;
319	        }
320	        Ok(byte)
321	    }
322	
323	    fn can_read(&self) -> bool {
324	        self.inner.slices.get(self.cursor.slice).is_some()
325	    }
326	}
