328	impl BacktrackableReader for ZBufReader<'_> {
329	    type Mark = ZBufPos;
330	
331	    fn mark(&mut self) -> Self::Mark {
332	        self.cursor
333	    }
334	
335	    fn rewind(&mut self, mark: Self::Mark) -> bool {
336	        self.cursor = mark;
337	        true
338	    }
339	}
340	
341	impl SiphonableReader for ZBufReader<'_> {
342	    fn siphon<W>(&mut self, writer: &mut W) -> Result<NonZeroUsize, DidntSiphon>
343	    where
344	        W: Writer,
345	    {
346	        let mut read = 0;
347	        while let Some(slice) = self.inner.slices.get(self.cursor.slice) {
348	            // Subslice from the current read slice
349	            // SAFETY: self.cursor.byte is ensured by the reader.
350	            let from = crate::unsafe_slice!(slice.as_slice(), self.cursor.byte..);
351	            // Copy the slice content
352	            match writer.write(from) {
353	                Ok(len) => {
354	                    // Update the counter
355	                    read += len.get();
356	                    // Move the byte cursor
357	                    self.cursor.byte += len.get();
358	                    // We consumed all the current read slice, move to the next slice
359	                    if self.cursor.byte == slice.len() {
360	                        self.cursor.slice += 1;
361	                        self.cursor.byte = 0;
362	                    }
363	                }
364	                Err(_) => {
365	                    return NonZeroUsize::new(read).ok_or(DidntSiphon);
366	                }
367	            }
368	        }
369	        NonZeroUsize::new(read).ok_or(DidntSiphon)
370	    }
371	}
372	
373	#[cfg(feature = "std")]
374	impl io::Read for ZBufReader<'_> {
375	    fn read(&mut self, buf: &mut [u8]) -> io::Result<usize> {
376	        match <Self as Reader>::read(self, buf) {
377	            Ok(n) => Ok(n.get()),
378	            Err(_) => Ok(0),
379	        }
380	    }
381	}
382	
383	impl AdvanceableReader for ZBufReader<'_> {
384	    fn skip(&mut self, offset: usize) -> Result<(), DidntRead> {
385	        let mut remaining_offset = offset;
386	        while remaining_offset > 0 {
387	            let s = self.inner.slices.get(self.cursor.slice).ok_or(DidntRead)?;
388	            let remains_in_current_slice = s.len() - self.cursor.byte;
389	            let advance = remaining_offset.min(remains_in_current_slice);
390	            remaining_offset -= advance;
391	            self.cursor.byte += advance;
392	            if self.cursor.byte == s.len() {
393	                self.cursor.slice += 1;
394	                self.cursor.byte = 0;
395	            }
396	        }
397	        Ok(())
398	    }
399	
400	    fn backtrack(&mut self, offset: usize) -> Result<(), DidntRead> {
401	        let mut remaining_offset = offset;
402	        while remaining_offset > 0 {
403	            let backtrack = remaining_offset.min(self.cursor.byte);
404	            remaining_offset -= backtrack;
405	            self.cursor.byte -= backtrack;
406	            if self.cursor.byte == 0 {
407	                if self.cursor.slice == 0 {
408	                    break;
409	                }
410	                self.cursor.slice -= 1;
411	                self.cursor.byte = self
412	                    .inner
413	                    .slices
414	                    .get(self.cursor.slice)
415	                    .ok_or(DidntRead)?
416	                    .len();
417	            }
418	        }
419	        if remaining_offset == 0 {
420	            Ok(())
421	        } else {
422	            Err(DidntRead)
423	        }
424	    }
425	}
426	
427	#[cfg(feature = "std")]
428	impl io::Seek for ZBufReader<'_> {
429	    fn seek(&mut self, pos: io::SeekFrom) -> io::Result<u64> {
430	        let current_pos = self
431	            .inner
432	            .slices()
433	            .take(self.cursor.slice)
434	            .fold(0, |acc, s| acc + s.len())
435	            + self.cursor.byte;
436	        let current_pos =
437	            i64::try_from(current_pos).map_err(|e| std::io::Error::other(e.to_string()))?;
438	
439	        let offset = match pos {
440	            std::io::SeekFrom::Start(s) => i64::try_from(s).unwrap_or(i64::MAX) - current_pos,
441	            std::io::SeekFrom::Current(s) => s,
442	            std::io::SeekFrom::End(s) => self.inner.len() as i64 + s - current_pos,
443	        };
444	        match self.advance(offset as isize) {
445	            Ok(()) => Ok((offset + current_pos) as u64),
446	            Err(_) => Err(std::io::Error::new(
447	                std::io::ErrorKind::InvalidInput,
448	                "InvalidInput",
449	            )),
450	        }
451	    }
452	}
453	
454	// ZSlice iterator
455	#[derive(Debug)]
456	pub struct ZBufSliceIterator<'a, 'b> {
457	    reader: &'a mut ZBufReader<'b>,
458	    remaining: usize,
459	}
460	
461	impl Iterator for ZBufSliceIterator<'_, '_> {
462	    type Item = ZSlice;
463	
464	    fn next(&mut self) -> Option<Self::Item> {
465	        if self.remaining == 0 {
466	            return None;
467	        }
468	
469	        // SAFETY: self.reader.cursor.slice is ensured by the reader.
470	        let slice =
471	            crate::unsafe_slice!(self.reader.inner.slices.as_ref(), self.reader.cursor.slice);
472	        let start = self.reader.cursor.byte;
473	        // SAFETY: self.reader.cursor.byte is ensured by the reader.
474	        let current = crate::unsafe_slice!(slice, start..);
475	        let len = current.len();
476	        match self.remaining.cmp(&len) {
477	            cmp::Ordering::Less => {
478	                let end = start + self.remaining;
479	                let slice = slice.subslice(start..end);
480	                self.reader.cursor.byte = end;
481	                self.remaining = 0;
482	                slice
483	            }
484	            cmp::Ordering::Equal => {
485	                let end = start + self.remaining;
486	                let slice = slice.subslice(start..end);
487	                self.reader.cursor.slice += 1;
488	                self.reader.cursor.byte = 0;
489	                self.remaining = 0;
490	                slice
491	            }
492	            cmp::Ordering::Greater => {
493	                let end = start + len;
494	                let slice = slice.subslice(start..end);
495	                self.reader.cursor.slice += 1;
496	                self.reader.cursor.byte = 0;
497	                self.remaining -= len;
498	                slice
499	            }
500	        }
501	    }
502	
503	    fn size_hint(&self) -> (usize, Option<usize>) {
504	        (1, None)
505	    }
506	}
