508	// Writer
509	#[derive(Debug)]
510	pub struct ZBufWriter<'a> {
511	    inner: NonNull<ZBuf>,
512	    zslice_writer: Option<ZSliceWriter<'a>>,
513	}
514	
515	impl<'a> ZBufWriter<'a> {
516	    #[inline]
517	    fn zslice_writer(&mut self) -> &mut ZSliceWriter<'a> {
518	        if self.zslice_writer.is_none() {
519	            // SAFETY: `self.inner` is valid as guaranteed by `self.writer` borrow.
520	            let zbuf = unsafe { self.inner.as_mut() };
521	            zbuf.slices.push(ZSlice::empty());
522	            self.zslice_writer = zbuf.slices.last_mut().unwrap().writer();
523	        }
524	        self.zslice_writer.as_mut().unwrap()
525	    }
526	}
527	
528	impl<'a> HasWriter for &'a mut ZBuf {
529	    type Writer = ZBufWriter<'a>;
530	
531	    fn writer(self) -> Self::Writer {
532	        ZBufWriter {
533	            inner: NonNull::new(self).unwrap(),
534	            zslice_writer: self.opt_zslice_writer(),
535	        }
536	    }
537	}
538	
539	impl Writer for ZBufWriter<'_> {
540	    fn write(&mut self, bytes: &[u8]) -> Result<NonZeroUsize, DidntWrite> {
541	        self.zslice_writer().write(bytes)
542	    }
543	
544	    fn write_exact(&mut self, bytes: &[u8]) -> Result<(), DidntWrite> {
545	        self.zslice_writer().write_exact(bytes)
546	    }
547	
548	    fn remaining(&self) -> usize {
549	        usize::MAX
550	    }
551	
552	    fn write_zslice(&mut self, slice: &ZSlice) -> Result<(), DidntWrite> {
553	        self.zslice_writer = None;
554	        // SAFETY: `self.inner` is valid as guaranteed by `self.writer` borrow,
555	        // and `self.writer` has been overwritten.
556	        unsafe { self.inner.as_mut() }.push_zslice(slice.clone());
557	        Ok(())
558	    }
559	
560	    /// # Safety
561	    ///
562	    /// The `write` closure must return the number of bytes actually written to the slice,
563	    /// which must be less than or equal to `len`.
564	    unsafe fn with_slot<F>(&mut self, len: usize, write: F) -> Result<NonZeroUsize, DidntWrite>
565	    where
566	        F: FnOnce(&mut [u8]) -> usize,
567	    {
568	        // SAFETY: Same precondition as this function. Call to `with_slot` is safe because
569	        // the requirements are passed through.
570	        unsafe { self.zslice_writer().with_slot(len, write) }
571	    }
572	}
573	
574	impl BacktrackableWriter for ZBufWriter<'_> {
575	    type Mark = ZBufPos;
576	
577	    fn mark(&mut self) -> Self::Mark {
578	        let byte = self.zslice_writer.as_mut().map(|w| w.mark());
579	        // SAFETY: `self.inner` is valid as guaranteed by `self.writer` borrow.
580	        let zbuf = unsafe { self.inner.as_mut() };
581	        ZBufPos {
582	            slice: zbuf.slices.len(),
583	            byte: byte
584	                .or_else(|| Some(zbuf.opt_zslice_writer()?.mark()))
585	                .unwrap_or(0),
586	        }
587	    }
588	
589	    fn rewind(&mut self, mark: Self::Mark) -> bool {
590	        // SAFETY: `self.inner` is valid as guaranteed by `self.writer` borrow,
591	        // and `self.writer` is reassigned after modification.
592	        let zbuf = unsafe { self.inner.as_mut() };
593	        zbuf.slices.truncate(mark.slice);
594	        self.zslice_writer = zbuf.opt_zslice_writer();
595	        if let Some(writer) = &mut self.zslice_writer {
596	            writer.rewind(mark.byte);
597	        }
598	        true
599	    }
600	}
601	
602	#[cfg(feature = "std")]
603	impl io::Write for ZBufWriter<'_> {
604	    fn write(&mut self, buf: &[u8]) -> io::Result<usize> {
605	        if buf.is_empty() {
606	            return Ok(0);
607	        }
608	        match <Self as Writer>::write(self, buf) {
609	            Ok(n) => Ok(n.get()),
610	            Err(_) => Err(io::ErrorKind::UnexpectedEof.into()),
611	        }
612	    }
613	
614	    fn flush(&mut self) -> io::Result<()> {
615	        Ok(())
616	    }
617	}
618	
619	#[cfg(feature = "test")]
620	impl ZBuf {
621	    #[doc(hidden)]
622	    pub fn rand(len: usize) -> Self {
623	        let mut zbuf = ZBuf::empty();
624	        zbuf.push_zslice(ZSlice::rand(len));
625	        zbuf
626	    }
627	}
628	
629	mod tests {
630	    #[test]
631	    fn zbuf_eq() {
632	        use super::{ZBuf, ZSlice};
633	
634	        let slice: ZSlice = [0u8, 1, 2, 3, 4, 5, 6, 7].to_vec().into();
635	
636	        let mut zbuf1 = ZBuf::empty();
637	        zbuf1.push_zslice(slice.subslice(..4).unwrap());
638	        zbuf1.push_zslice(slice.subslice(4..8).unwrap());
639	
640	        let mut zbuf2 = ZBuf::empty();
641	        zbuf2.push_zslice(slice.subslice(..1).unwrap());
642	        zbuf2.push_zslice(slice.subslice(1..4).unwrap());
643	        zbuf2.push_zslice(slice.subslice(4..8).unwrap());
644	
645	        assert_eq!(zbuf1, zbuf2);
646	
647	        let mut zbuf1 = ZBuf::empty();
648	        zbuf1.push_zslice(slice.subslice(2..4).unwrap());
649	        zbuf1.push_zslice(slice.subslice(4..8).unwrap());
650	
651	        let mut zbuf2 = ZBuf::empty();
652	        zbuf2.push_zslice(slice.subslice(2..3).unwrap());
653	        zbuf2.push_zslice(slice.subslice(3..6).unwrap());
654	        zbuf2.push_zslice(slice.subslice(6..8).unwrap());
655	
656	        assert_eq!(zbuf1, zbuf2);
657	    }
658	
659	    #[cfg(feature = "std")]
660	    #[test]
661	    fn zbuf_seek() {
662	        use std::io::Seek;
663	
664	        use super::{HasReader, ZBuf};
665	        use crate::reader::Reader;
666	
667	        let mut buf = ZBuf::empty();
668	        buf.push_zslice([0u8, 1u8, 2u8, 3u8].into());
669	        buf.push_zslice([4u8, 5u8, 6u8, 7u8, 8u8].into());
670	        buf.push_zslice([9u8, 10u8, 11u8, 12u8, 13u8, 14u8].into());
671	        let mut reader = buf.reader();
672	
673	        assert_eq!(reader.stream_position().unwrap(), 0);
674	        assert_eq!(reader.read_u8().unwrap(), 0);
675	        assert_eq!(reader.seek(std::io::SeekFrom::Current(6)).unwrap(), 7);
676	        assert_eq!(reader.read_u8().unwrap(), 7);
677	        assert_eq!(reader.seek(std::io::SeekFrom::Current(-5)).unwrap(), 3);
678	        assert_eq!(reader.read_u8().unwrap(), 3);
679	        assert_eq!(reader.seek(std::io::SeekFrom::Current(10)).unwrap(), 14);
680	        assert_eq!(reader.read_u8().unwrap(), 14);
681	        reader.seek(std::io::SeekFrom::Current(100)).unwrap_err();
682	
683	        assert_eq!(reader.seek(std::io::SeekFrom::Start(0)).unwrap(), 0);
684	        assert_eq!(reader.read_u8().unwrap(), 0);
685	        assert_eq!(reader.seek(std::io::SeekFrom::Start(12)).unwrap(), 12);
686	        assert_eq!(reader.read_u8().unwrap(), 12);
687	        assert_eq!(reader.seek(std::io::SeekFrom::Start(15)).unwrap(), 15);
688	        reader.read_u8().unwrap_err();
689	        reader.seek(std::io::SeekFrom::Start(100)).unwrap_err();
690	
691	        assert_eq!(reader.seek(std::io::SeekFrom::End(0)).unwrap(), 15);
692	        reader.read_u8().unwrap_err();
693	        assert_eq!(reader.seek(std::io::SeekFrom::End(-5)).unwrap(), 10);
694	        assert_eq!(reader.read_u8().unwrap(), 10);
695	        assert_eq!(reader.seek(std::io::SeekFrom::End(-15)).unwrap(), 0);
696	        assert_eq!(reader.read_u8().unwrap(), 0);
697	        reader.seek(std::io::SeekFrom::End(-20)).unwrap_err();
698	
699	        assert_eq!(reader.seek(std::io::SeekFrom::Start(10)).unwrap(), 10);
700	        reader.seek(std::io::SeekFrom::Current(-100)).unwrap_err();
